import React, { useState, useEffect, useRef } from 'react';
import {
  Container,
  Box,
  Paper,
  Typography,
  TextField,
  Select,
  MenuItem,
  Button,
  FormControl,
  InputLabel,
  Grid,
  Card,
  CardContent,
  IconButton,
  List,
  ListItem,
  ListItemText,
  Collapse,
  Divider,
  Menu,
  Chip,
  Alert,
  FormHelperText
} from '@mui/material';
import {
  Save,
  CalendarMonth,
  ExpandMore,
  ExpandLess,
  Flag,
  Schedule,
  Info,
  Loop,
  RemoveCircle,
  Delete,
  Article
} from '@mui/icons-material';

function App() {
  const [formData, setFormData] = useState({
    week: '',
    type: '',
    date: '',
    action: ''
  });

  const [weeks, setWeeks] = useState([]);
  const [types, setTypes] = useState([]);
  const [actions, setActions] = useState([]);
  const [expandedNodes, setExpandedNodes] = useState(new Set());
  const [contextMenu, setContextMenu] = useState({ visible: false, x: 0, y: 0, actionId: null });
  const [actionStatuses, setActionStatuses] = useState({});
  const [excludedFromReport, setExcludedFromReport] = useState(new Set());
  const [errors, setErrors] = useState({
    week: false,
    type: false,
    date: false,
    action: false
  });
  const [anchorEl, setAnchorEl] = useState(null);
  const [selectedActionId, setSelectedActionId] = useState(null);
  const [showOnlyWithStatus, setShowOnlyWithStatus] = useState(false);
  const [editingActionId, setEditingActionId] = useState(null);
  const dateInputRef = useRef(null);

  useEffect(() => {
    // Load weeks from text file
    fetch('/data/weeks.txt')
      .then(response => response.text())
      .then(data => {
        const weekList = data.split('\n').filter(line => line.trim());
        setWeeks(weekList);
      })
      .catch(error => {
        console.error('Error loading weeks:', error);
        // Fallback data
        setWeeks(['1. Hafta', '2. Hafta', '3. Hafta', '4. Hafta']);
      });

    // Load types from text file
    fetch('/data/types.txt')
      .then(response => response.text())
      .then(data => {
        const typeList = data.split('\n').filter(line => line.trim());
        setTypes(typeList);
      })
      .catch(error => {
        console.error('Error loading types:', error);
        // Fallback data
        setTypes(['Planlama', 'Geliştirme', 'Test', 'Dokümantasyon']);
      });
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Clear error when user enters data
    if (value.trim()) {
      setErrors(prev => ({ ...prev, [name]: false }));
    }
  };

  const handleCalendarClick = () => {
    dateInputRef.current?.showPicker();
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    const newErrors = {
      week: !formData.week,
      type: !formData.type,
      date: !formData.date,
      action: !formData.action
    };

    setErrors(newErrors);

    if (Object.values(newErrors).some(error => error)) {
      return;
    }

    if (editingActionId) {
      // Update existing action
      setActions(prev => prev.map(action => 
        action.id === editingActionId 
          ? { ...action, ...formData, timestamp: new Date().toLocaleString('tr-TR') }
          : action
      ));
      setEditingActionId(null);
    } else {
      // Create new action
      const newAction = {
        id: Date.now(),
        ...formData,
        timestamp: new Date().toLocaleString('tr-TR')
      };

      setActions(prev => [...prev, newAction]);

      // Auto-expand the week for the new action
      setExpandedNodes(prev => new Set([...prev, formData.week]));
    }

    // Reset form and errors (keep week selected)
    setFormData({
      week: formData.week,
      type: '',
      date: '',
      action: ''
    });
    setErrors({
      week: false,
      type: false,
      date: false,
      action: false
    });
  };

  const toggleNode = (nodeId) => {
    setExpandedNodes(prev => {
      const newSet = new Set(prev);
      if (newSet.has(nodeId)) {
        newSet.delete(nodeId);
      } else {
        newSet.add(nodeId);
      }
      return newSet;
    });
  };

  const handleContextMenu = (e, actionId) => {
    e.preventDefault();
    setSelectedActionId(actionId);
    setAnchorEl(e.currentTarget);
  };

  const handleCloseContextMenu = () => {
    setAnchorEl(null);
    setSelectedActionId(null);
  };

  const handleSetStatus = (status) => {
    if (selectedActionId) {
      setActionStatuses(prev => ({ ...prev, [selectedActionId]: status }));
    }
    handleCloseContextMenu();
  };

  const handleRemoveFromReport = () => {
    if (selectedActionId) {
      setExcludedFromReport(prev => new Set([...prev, selectedActionId]));
    }
    handleCloseContextMenu();
  };

  const handleDeleteAction = () => {
    if (selectedActionId) {
      setActions(prev => prev.filter(a => a.id !== selectedActionId));
    }
    handleCloseContextMenu();
  };

  const handleActionClick = (action) => {
    setEditingActionId(action.id);
    setFormData({
      week: action.week,
      type: action.type,
      date: action.date,
      action: action.action
    });
  };

  const handleCancelEdit = () => {
    setEditingActionId(null);
    setFormData({
      week: formData.week,
      type: '',
      date: '',
      action: ''
    });
    setErrors({
      week: false,
      type: false,
      date: false,
      action: false
    });
  };

  const toggleStatusFilter = () => {
    setShowOnlyWithStatus(prev => !prev);
  };

  const groupActionsByWeek = () => {
    const grouped = {};
    actions.filter(a => !excludedFromReport.has(a.id)).forEach(action => {
      // Filter by selected week - only show selected week's actions
      if (formData.week && action.week !== formData.week) {
        return; // Skip if not the selected week
      }

      // Apply status filter - show only actions with any status assigned
      if (showOnlyWithStatus) {
        const actionStatus = actionStatuses[action.id];
        if (!actionStatus) {
          return; // Skip this action if it has no status
        }
      }

      if (!grouped[action.week]) {
        grouped[action.week] = [];
      }
      grouped[action.week].push(action);
    });
    return grouped;
  };

  const groupedActions = groupActionsByWeek();

  const getStatusColor = (status) => {
    switch (status) {
      case 'highlight': return 'error';
      case 'lowlight': return 'default';
      case 'waiting': return 'warning';
      case 'information': return 'info';
      case 'progress': return 'success';
      default: return 'default';
    }
  };

  return (
    <Container maxWidth="lg" sx={{ py: 3 }}>
      <Paper
        elevation={3}
        sx={{
          p: 4,
          mb: 3,
          background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)',
          color: 'white',
          borderRadius: 3
        }}
      >
        <Typography variant="h4" fontWeight="bold">
          Haftalık Aksiyon Takibi
        </Typography>
      </Paper>

      <Grid container spacing={3} sx={{ alignItems: 'stretch' }}>
        <Grid item xs={12} md={4} sx={{ display: 'flex', flex: '0 0 35%', maxWidth: '35%' }}>
          <Card elevation={2} sx={{ width: '100%' }}>
            <CardContent>
              <Typography variant="h6" gutterBottom sx={{ borderBottom: 2, borderColor: 'primary.main', pb: 1 }}>
                {editingActionId ? 'Aksiyonu Güncelle' : 'Yeni Aksiyon Ekle'}
              </Typography>

              <Box component="form" onSubmit={handleSubmit} sx={{ mt: 2 }}>
                <FormControl fullWidth margin="normal" error={errors.week}>
                  <InputLabel>Hafta</InputLabel>
                  <Select
                    name="week"
                    value={formData.week}
                    onChange={handleInputChange}
                    label="Hafta"
                  >
                    <MenuItem value="">
                      <em>Hafta seçin...</em>
                    </MenuItem>
                    {weeks.map((week, index) => (
                      <MenuItem key={index} value={week}>
                        {week}. Hafta
                      </MenuItem>
                    ))}
                  </Select>
                  {errors.week && <FormHelperText>Lütfen hafta seçin</FormHelperText>}
                </FormControl>

                <FormControl fullWidth margin="normal" error={errors.type}>
                  <InputLabel>Tür</InputLabel>
                  <Select
                    name="type"
                    value={formData.type}
                    onChange={handleInputChange}
                    label="Tür"
                  >
                    <MenuItem value="">
                      <em>Tür seçin...</em>
                    </MenuItem>
                    {types.map((type, index) => (
                      <MenuItem key={index} value={type}>
                        {type}
                      </MenuItem>
                    ))}
                  </Select>
                  {errors.type && <FormHelperText>Lütfen tür seçin</FormHelperText>}
                </FormControl>

                <TextField
                  fullWidth
                  margin="normal"
                  type="date"
                  name="date"
                  label="Tarih"
                  value={formData.date}
                  onChange={handleInputChange}
                  error={errors.date}
                  helperText={errors.date ? "Lütfen tarih girin" : ""}
                  InputLabelProps={{ shrink: true }}
                  inputRef={dateInputRef}
                  InputProps={{
                    endAdornment: (
                      <IconButton onClick={() => dateInputRef.current?.showPicker?.()}>
                        <CalendarMonth />
                      </IconButton>
                    )
                  }}
                />

                <TextField
                  fullWidth
                  multiline
                  rows={4}
                  margin="normal"
                  name="action"
                  label="Aksiyon"
                  value={formData.action}
                  onChange={handleInputChange}
                  error={errors.action}
                  helperText={errors.action ? "Lütfen aksiyon açıklaması girin" : ""}
                  placeholder="Aksiyonu detaylı olarak yazın..."
                />

                <Button
                  type="submit"
                  variant="contained"
                  fullWidth
                  sx={{ mt: 2 }}
                  startIcon={<Save />}
                  color={editingActionId ? 'secondary' : 'primary'}
                >
                  {editingActionId ? 'Güncelle' : 'Kaydet'}
                </Button>
                {editingActionId && (
                  <Button
                    variant="outlined"
                    fullWidth
                    sx={{ mt: 1 }}
                    onClick={handleCancelEdit}
                  >
                    İptal
                  </Button>
                )}
              </Box>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={8} sx={{ display: 'flex', flexDirection: 'column', flex: '0 0 65%', maxWidth: '65%' }}>
          <Card elevation={2} sx={{ mb: 2 }}>
            <CardContent>
              <Typography variant="h6" gutterBottom sx={{ borderBottom: 2, borderColor: 'primary.main', pb: 1 }}>
                Haftalık Rapor
              </Typography>
              <Alert severity="info" sx={{ mt: 2 }}>
                Bu hafta toplam {actions.length} aksiyon kaydedildi.
              </Alert>
            </CardContent>
          </Card>

          <Card elevation={2} sx={{ flex: 1 }}>
            <CardContent sx={{ height: '100%' }}>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', borderBottom: 2, borderColor: 'primary.main', pb: 1, mb: 2 }}>
                <Typography variant="h6">
                  Ekip Aksiyonları
                </Typography>
                <Button
                  variant={showOnlyWithStatus ? 'contained' : 'outlined'}
                  size="small"
                  onClick={toggleStatusFilter}
                  startIcon={<Flag fontSize="small" />}
                  sx={{ fontSize: '12px' }}
                >
                  {showOnlyWithStatus ? 'Tümünü Göster' : 'Statülü Olanlar'}
                </Button>
              </Box>

              {actions.length === 0 ? (
                <Box sx={{ textAlign: 'center', py: 4 }}>
                  <Article sx={{ fontSize: 48, color: 'text.secondary', mb: 2 }} />
                  <Typography variant="h6" color="text.secondary">
                    Henüz kayıt yok
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    Yeni bir aksiyon ekleyerek başlayın
                  </Typography>
                </Box>
              ) : (
                <List>
                  {Object.entries(groupedActions).map(([week, weekActions]) => (
                    <Box key={week}>
                      <ListItem
                        button
                        onClick={() => toggleNode(week)}
                        sx={{
                          backgroundColor: 'grey.50',
                          borderRadius: 1,
                          mb: 1,
                          '&:hover': { backgroundColor: 'grey.100' }
                        }}
                      >
                        <ListItemText
                          primary={
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                              <Box
                                sx={{
                                  width: 8,
                                  height: 8,
                                  borderRadius: '50%',
                                  backgroundColor: 'primary.main'
                                }}
                              />
                              <Typography fontWeight="medium">
                                {week}. Hafta ({weekActions.length} aksiyon)
                              </Typography>
                            </Box>
                          }
                        />
                        {expandedNodes.has(week) ? <ExpandLess /> : <ExpandMore />}
                      </ListItem>

                      <Collapse in={expandedNodes.has(week)} timeout="auto" unmountOnExit>
                        <List component="div" disablePadding>
                          {weekActions.map(action => (
                            <ListItem
                              key={action.id}
                              sx={{
                                pl: 4,
                                py: 1,
                                cursor: 'pointer',
                                '&:hover': { backgroundColor: 'grey.50' },
                                borderLeft: editingActionId === action.id 
                                  ? '3px solid #6366f1'
                                  : actionStatuses[action.id]
                                    ? `3px solid ${
                                        actionStatuses[action.id] === 'highlight' ? '#ef4444' :
                                        actionStatuses[action.id] === 'lowlight' ? '#6b7280' :
                                        actionStatuses[action.id] === 'waiting' ? '#f59e0b' :
                                        actionStatuses[action.id] === 'information' ? '#3b82f6' :
                                        actionStatuses[action.id] === 'progress' ? '#10b981' : 'transparent'
                                      }`
                                    : '3px solid transparent'
                              }}
                              onClick={() => handleActionClick(action)}
                              onContextMenu={(e) => handleContextMenu(e, action.id)}
                            >
                              <ListItemText
                                primary={
                                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                                    <Chip
                                      label={action.type}
                                      size="small"
                                      color={getStatusColor(actionStatuses[action.id])}
                                      sx={{ fontWeight: 'bold', textTransform: 'uppercase' }}
                                    />
                                    <Typography variant="body2" color="text.secondary">
                                      -
                                    </Typography>
                                    <Typography variant="body2" sx={{ flex: 1, wordWrap: 'break-word', whiteSpace: 'normal' }}>
                                      {action.action}
                                    </Typography>
                                  </Box>
                                }
                              />
                            </ListItem>
                          ))}
                        </List>
                      </Collapse>
                      <Divider sx={{ my: 1 }} />
                    </Box>
                  ))}
                </List>
              )}
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={handleCloseContextMenu}
      >
        <MenuItem onClick={() => handleSetStatus('highlight')}>
          <Flag fontSize="small" color="error" sx={{ mr: 1 }} />
          Highlight
        </MenuItem>
        <MenuItem onClick={() => handleSetStatus('lowlight')}>
          <Flag fontSize="small" sx={{ mr: 1 }} />
          LowLight
        </MenuItem>
        <MenuItem onClick={() => handleSetStatus('waiting')}>
          <Schedule fontSize="small" color="warning" sx={{ mr: 1 }} />
          Waiting For Ex. Support
        </MenuItem>
        <MenuItem onClick={() => handleSetStatus('information')}>
          <Info fontSize="small" color="info" sx={{ mr: 1 }} />
          Information
        </MenuItem>
        <MenuItem onClick={() => handleSetStatus('progress')}>
          <Loop fontSize="small" color="success" sx={{ mr: 1 }} />
          Progress
        </MenuItem>
        <Divider />
        <MenuItem onClick={handleRemoveFromReport} sx={{ color: 'error.main' }}>
          <RemoveCircle fontSize="small" sx={{ mr: 1 }} />
          Haftalık Rapordan Çıkar
        </MenuItem>
        <MenuItem onClick={handleDeleteAction} sx={{ color: 'error.main' }}>
          <Delete fontSize="small" sx={{ mr: 1 }} />
          Sil
        </MenuItem>
      </Menu>
    </Container>
  );
}

export default App;
